class Solution:
  def validateRefName(self, str: str) -> bool:
    # Check if the ref name starts with a hyphen
    if str[0] == '-':
      return False
    # Check for invalid characters
    if not re.match(r'^[a-zA-Z0-9-]+$', str):
      return False
    # Check if the ref name is at least 1 character long
    if len(str) < 1:
      return False
    return True
